# test_flatten_dict.py

import pytest

from your_module import flatten_dict


def test_flatten_dict_happy_path():
    data = {
        "a": 1,
        "b": {
            "c": 2,
            "d": {
                "e": 3,
            },
        },
    }

    result = flatten_dict(data)

    assert result == {
        "a": 1,
        "b.c": 2,
        "b.d.e": 3,
    }


def test_flatten_dict_with_custom_separator():
    data = {
        "a": {
            "b": {
                "c": 1,
            },
        },
    }

    result = flatten_dict(data, sep="_")

    assert result == {
        "a_b_c": 1,
    }


def test_flatten_dict_with_parent_key():
    data = {
        "b": {
            "c": 1,
        },
    }

    result = flatten_dict(data, parent_key="a")

    assert result == {
        "a.b.c": 1,
    }


def test_flatten_dict_empty_dict():
    assert flatten_dict({}) == {}


def test_flatten_dict_nested_empty_dict_is_omitted():
    data = {
        "a": {},
        "b": 1,
    }

    result = flatten_dict(data)

    assert result == {
        "b": 1,
    }


def test_flatten_dict_preserves_non_dict_values():
    data = {
        "a": None,
        "b": False,
        "c": 0,
        "d": [],
        "e": [1, 2, 3],
        "f": "value",
    }

    result = flatten_dict(data)

    assert result == {
        "a": None,
        "b": False,
        "c": 0,
        "d": [],
        "e": [1, 2, 3],
        "f": "value",
    }


def test_flatten_dict_deeply_nested_dict():
    data = {
        "a": {
            "b": {
                "c": {
                    "d": {
                        "e": 42,
                    },
                },
            },
        },
    }

    result = flatten_dict(data)

    assert result == {
        "a.b.c.d.e": 42,
    }


def test_flatten_dict_key_collision_last_value_wins():
    data = {
        "a": {
            "b": 1,
        },
        "a.b": 2,
    }

    result = flatten_dict(data)

    assert result == {
        "a.b": 2,
    }


def test_flatten_dict_handles_non_string_top_level_keys():
    data = {
        1: "one",
        "nested": {
            2: "two",
        },
    }

    result = flatten_dict(data)

    assert result == {
        1: "one",
        "nested.2": "two",
    }


@pytest.mark.parametrize("invalid_input", [None, [], (), "not a dict", 123])
def test_flatten_dict_invalid_input_raises_attribute_error(invalid_input):
    with pytest.raises(AttributeError):
        flatten_dict(invalid_input)
